-- Canonical DDL for naap.canonical_session_current_store.
-- Source of truth: this file. The resolver and MVs write rows;
-- this declaration governs the physical schema.
-- Apply with scripts/apply-store-ddl.sh; drift is caught by
-- warehouse/tests/test_store_ddl_drift.sql.

CREATE TABLE IF NOT EXISTS naap.canonical_session_current_store (`canonical_session_key` String, `org` LowCardinality(String), `stream_id` String, `request_id` String, `current_selection_event_id` Nullable(String), `current_selection_ts` Nullable(DateTime64(3, 'UTC')), `canonical_pipeline` String, `canonical_model` Nullable(String), `gpu_id` Nullable(String), `started_at` Nullable(DateTime64(3, 'UTC')), `last_seen` DateTime64(3, 'UTC'), `startup_latency_ms` Nullable(Float64), `e2e_latency_ms` Nullable(Float64), `prompt_to_playable_latency_ms` Nullable(Float64), `requested_seen` UInt8 DEFAULT 0, `started` UInt8, `playable_seen` UInt8, `selection_outcome` LowCardinality(String) DEFAULT 'unknown', `no_orch` UInt8, `completed` UInt8, `swap_count` UInt64, `restart_seen` UInt8, `error_seen` UInt8, `degraded_input_seen` UInt8, `degraded_inference_seen` UInt8, `status_sample_count` UInt64, `status_error_sample_count` UInt64, `startup_error_count` UInt64 DEFAULT 0, `excusable_error_count` UInt64 DEFAULT 0, `loading_only_session` UInt8, `zero_output_fps_session` UInt8, `health_signal_count` UInt64, `health_expected_signal_count` UInt64, `health_signal_coverage_ratio` Float64, `startup_outcome` LowCardinality(String), `excusal_reason` LowCardinality(String) DEFAULT 'none', `has_ambiguous_identity` UInt8, `has_snapshot_match` UInt8, `is_hardware_less` UInt8, `is_stale` UInt8, `attribution_reason` LowCardinality(String), `attribution_status` LowCardinality(String), `attributed_orch_address` Nullable(String), `attributed_orch_uri` Nullable(String), `attribution_snapshot_ts` Nullable(DateTime64(3, 'UTC')), `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `materialized_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(materialized_at) PARTITION BY (org, toYYYYMM(last_seen)) ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;
